import { generateText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

const { text, toolResults } = await generateText({
  model: openai("gpt-4o"),
  tools: {
    getStockPrice: tool({
      description: "Get the current stock price for a ticker symbol.",
      parameters: z.object({
        ticker: z.string().describe("The stock ticker symbol, e.g. AAPL"),
      }),
      execute: async ({ ticker }) => {
        // Replace with a real API call
        const prices: Record<string, number> = { AAPL: 185.5, GOOG: 175.2 };
        return { ticker, price: prices[ticker] ?? null };
      },
    }),
  },
  prompt: "What is the current price of Apple stock?",
});

console.log(text);
// "The current price of Apple (AAPL) is $185.50."

for (const result of toolResults) {
  console.log(result.toolName, result.result);
  // getStockPrice { ticker: "AAPL", price: 185.5 }
}

import { generateText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

const { text } = await generateText({
  model: openai("gpt-4o"),
  tools: {
    search: tool({
      description: "Search the web for a query.",
      parameters: z.object({ query: z.string() }),
      execute: async ({ query }) => [{ title: "Result", snippet: "..." }],
    }),
    translate: tool({
      description: "Translate text to a target language.",
      parameters: z.object({
        text: z.string(),
        targetLanguage: z.string().describe("BCP-47 language code, e.g. 'fr', 'ja'"),
      }),
      execute: async ({ text, targetLanguage }) => ({ translated: `[${targetLanguage}] ${text}` }),
    }),
  },
  maxSteps: 5,
  prompt: "Search for the capital of Japan and translate the result to French.",
});

import { generateText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

// Force the model to always call a specific tool
const { toolCalls } = await generateText({
  model: openai("gpt-4o"),
  tools: {
    classify: tool({
      description: "Classify the sentiment of a text.",
      parameters: z.object({
        text: z.string(),
        sentiment: z.enum(["positive", "negative", "neutral"]),
      }),
      execute: async (args) => args,
    }),
  },
  toolChoice: { type: "tool", toolName: "classify" },
  prompt: "This product is absolutely terrible.",
});

console.log(toolCalls[0].args.sentiment);  // "negative"

// Other toolChoice values:
// "auto"     — model decides whether to call a tool (default)
// "required" — model must call at least one tool
// "none"     — model must not call any tool

import { generateText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

