}

import { z } from "zod";

// Simple flat schema — best for most tools
const simple = z.object({
  city: z.string().describe("City name"),
  country: z.string().describe("ISO 3166-1 alpha-2 country code"),
});

// Array of items
const list = z.object({
  items: z.array(
    z.object({
      name: z.string(),
      quantity: z.number().int().min(1),
    })
  ).describe("List of items to order"),
});

// Optional fields with defaults
const withOptional = z.object({
  query: z.string(),
  limit: z.number().int().default(10).describe("Max results, default 10"),
  language: z.string().optional().describe("BCP-47 code, defaults to 'en'"),
});

import { generateText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

// When the model calls multiple tools in one step, the SDK executes them in parallel
const { text, steps } = await generateText({
  model: openai("gpt-4o"),
  tools: {
    get_weather: tool({
      description: "Get weather for a city.",
      parameters: z.object({ city: z.string() }),
      execute: async ({ city }) => ({ city, temp: 18 }),
    }),
    get_time: tool({
      description: "Get the current local time for a city.",
      parameters: z.object({ city: z.string() }),
      execute: async ({ city }) => ({ city, time: "14:30" }),
    }),
  },
  maxSteps: 5,
  prompt: "What is the weather and local time in Tokyo right now?",
});

// Inspect individual steps
for (const step of steps) {
  console.log(`Step ${step.stepType}: ${step.toolCalls.length} tool calls`);
}

import { streamText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

const result = streamText({
  model: openai("gpt-4o"),
  tools: {
    lookup: tool({
      description: "Look up a definition.",
      parameters: z.object({ term: z.string() }),
      execute: async ({ term }) => ({ definition: `${term}: a sample definition.` }),
    }),
  },
  prompt: "Define 'recursion' and use it in a sentence.",
});

for await (const event of result.fullStream) {
  switch (event.type) {
    case "tool-call":
      console.log("Calling:", event.toolName, event.args);
      break;
    case "tool-result":
      console.log("Result:", event.result);
      break;
    case "text-delta":
      process.stdout.write(event.textDelta);
      break;
  }
}

import { generateText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

// Coerce string inputs to numbers — models sometimes stringify numbers
const priceTool = tool({
  description: "Fetch a price by product ID.",
  parameters: z.object({
    productId: z.coerce.number().int().positive()
      .describe("Numeric product ID"),
  }),
  execute: async ({ productId }) => ({ id: productId, price: 29.99 }),
});

import { generateText, tool } from "ai";
import { MockLanguageModelV1 } from "ai/test";
import { z } from "zod";

const mockModel = new MockLanguageModelV1({
  doGenerate: async () => ({
    rawCall: { rawPrompt: null, rawSettings: {} },
    finishReason: "tool-calls",
    usage: { promptTokens: 10, completionTokens: 5 },
    text: "",
    toolCalls: [{
      toolCallType: "function",
      toolCallId: "call-1",
      toolName: "getPrice",
      args: JSON.stringify({ ticker: "AAPL" }),
    }],
  }),
});

const { toolCalls } = await generateText({
  model: mockModel,
  tools: {
    getPrice: tool({
      description: "Get a stock price.",
      parameters: z.object({ ticker: z.string() }),
    }),
  },
  prompt: "Get AAPL price.",
});

console.assert(toolCalls[0].toolName === "getPrice");
console.assert(toolCalls[0].args.ticker === "AAPL");

// generateObject — extract structured data, no side effects
const { object } = await generateObject({
  model: openai("gpt-4o"),
  schema: z.object({
    category: z.enum(["support", "billing", "feature-request", "bug"]),
    priority: z.enum(["low", "medium", "high"]),
  }),
  prompt: "Classify: 'My subscription was charged twice.'",
});

// tool() with execute — trigger actions AND feed results back to model
const { text } = await generateText({
  model: openai("gpt-4o"),
  tools: {
    createTicket: tool({
      parameters: z.object({ category: z.string(), priority: z.string() }),
      execute: async (args) => { /* write to DB */ return { ticketId: "T-123" }; },
    }),
  },
  prompt: "Create a support ticket for a double billing issue.",
});
